  "note": "BSP CSG booleans",
  "code": "from cadbuildr.foundation import (  # pragma: allowlist secret\n    Part,\n    Sketch,\n    Point,\n    Line,\n    Polygon,\n    Circle,\n    Extrusion,\n    show,\n)\n\n\nclass LinePlaneCubeWithSideCylinders(Part):\n    \"\"\"Cube with one cylinder extruded from each side face.\n\n    Demonstrates Line.extrusion_plane(...) / Line.get_extrusion_plane(...)\n    to derive an oriented sketch plane from:\n    - line direction (plane X axis)\n    - extrusion direction hint (plane Y axis)\n    \"\"\"\n\n    def __init__(self, cube_size: float = 20.0, side_radius: float = 2.0, side_depth: float = 3.0):\n        super().__init__()\n\n        # Base cube from XY sketch.\n        base_sketch = Sketch(self.xy())\n        p1 = Point(base_sketch, 0.0, 0.0)\n        p2 = Point(base_sketch, cube_size, 0.0)\n        p3 = Point(base_sketch, cube_size, cube_size)\n        p4 = Point(base_sketch, 0.0, cube_size)\n        square = Polygon([Line(p1, p2), Line(p2, p3), Line(p3, p4), Line(p4, p1)])\n        self.add_operation(Extrusion(square, cube_size))\n\n        # Four side edges of the top perimeter in XY coordinates.\n        # The extrusion direction is +Z, so each line defines a vertical side face plane.\n        side_edges = [\n            Line(Point(base_sketch, 0.0, 0.0), Point(base_sketch, cube_size, 0.0)),\n            Line(Point(base_sketch, cube_size, 0.0), Point(base_sketch, cube_size, cube_size)),\n            Line(Point(base_sketch, cube_size, cube_size), Point(base_sketch, 0.0, cube_size)),\n            Line(Point(base_sketch, 0.0, cube_size), Point(base_sketch, 0.0, 0.0)),\n        ]\n\n        for idx, edge in enumerate(side_edges):\n            side_plane = edge.extrusion_plane(\n                extrusion_direction=[0.0, 0.0, 1.0],\n                name=f\"side_plane_{idx}\",\n            )\n            side_sketch = Sketch(side_plane)\n\n            # Circle centered halfway on the edge and halfway up cube height.\n            circle_center = Point(side_sketch, cube_size / 2.0, cube_size / 2.0)\n            circle = Circle(circle_center, side_radius)\n            # Extrude along side-plane normal (outward/inward depending on edge orientation).\n            self.add_operation(Extrusion(circle, side_depth))\n\n\nshow(LinePlaneCubeWithSideCylinders())\n"
