 "star": {
  "label": "star",
  "note": "custom polygon",
  "code": "from cadbuildr.foundation import *\nimport numpy as np\n\n\ndef get_star(inside_radius=20, outside_radius=40, num_points=5, height=10):\n    # initialize the component\n    star = Part()\n    # Create a Sketch from XY Plane\n    s = Sketch(star.xy())\n    # Start point\n    start_x, start_y = outside_radius, 0\n    s.pencil.move(start_x, start_y)\n\n    # draw a star\n    angle = 0\n    for i in range(num_points):\n        angle += np.pi / num_points\n        s.pencil.line_to(inside_radius * np.cos(angle), inside_radius * np.sin(angle))\n        angle += np.pi / num_points\n        if i != num_points - 1:\n            s.pencil.line_to(\n                outside_radius * np.cos(angle), outside_radius * np.sin(angle)\n            )\n\n    e = Extrusion(s.pencil.get_closed_polygon(), height)\n    star.add_operation(e)\n    star.paint(\"yellow\")\n    return star\n\n\nshow(get_star())\n"
 },
